import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Line } from "@react-three/drei";
import * as THREE from "three";
import "../style/NeuralNetwork3D.css";

const NODES = [
  { id: 0, pos: [-2.2,  1.5,  0.1], color: "#60a5fa" },
  { id: 1, pos: [-2.2,  0.5,  0.2], color: "#38bdf8" },
  { id: 2, pos: [-2.2, -0.5, -0.1], color: "#34d399" },
  { id: 3, pos: [-2.2, -1.5,  0.1], color: "#fbbf24" },
  { id: 4, pos: [ 0,    1.3,  0.3], color: "#e8b99a" },
  { id: 5, pos: [ 0,    0.2, -0.4], color: "#d4a574" },
  { id: 6, pos: [ 0,   -0.7,  0.5], color: "#c49a7a" },
  { id: 7, pos: [ 0,   -1.6, -0.2], color: "#b4846c" },
  { id: 8, pos: [ 2.2,  1.0,  0.0], color: "#4ade80" },
  { id: 9, pos: [ 2.2,  0,   -0.1], color: "#34d399" },
  { id: 10, pos: [ 2.2, -1.0,  0.1], color: "#86efac" },
];

const EDGES = [
  [0,4],[0,5],[0,6],[1,4],[1,5],[2,5],[3,4],[3,6],[3,7],
  [4,8],[4,10],[5,8],[5,9],[6,9],[7,8],[7,10],
];

const SIGNAL_EDGES = EDGES.filter((_, i) => i % 2 === 0);

/* ── Glow node — double-sphere with AdditiveBlending ── */
function GlowNode({ pos, color }) {
  const groupRef = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const s = 1 + Math.sin(clock.elapsedTime * 2.2 + phase.current) * 0.1;
    groupRef.current.scale.setScalar(s);
  });
  return (
    <group ref={groupRef} position={pos}>
      {/* Core */}
      <mesh>
        <sphereGeometry args={[0.1, 16, 16]} />
        <meshBasicMaterial color={color} />
      </mesh>
      {/* Inner halo */}
      <mesh>
        <sphereGeometry args={[0.2, 16, 16]} />
        <meshBasicMaterial color={color} transparent opacity={0.18}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
      {/* Outer bloom spread */}
      <mesh>
        <sphereGeometry args={[0.38, 16, 16]} />
        <meshBasicMaterial color={color} transparent opacity={0.07}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Animated edge ── */
function EdgeLine({ from, to }) {
  const phase = useRef(Math.random() * Math.PI * 2);
  const ref = useRef();
  const points = useMemo(() => [
    new THREE.Vector3(...from.pos),
    new THREE.Vector3(...to.pos),
  ], [from, to]);
  useFrame(({ clock }) => {
    if (!ref.current?.material) return;
    ref.current.material.opacity = 0.07 + Math.sin(clock.elapsedTime + phase.current) * 0.04;
  });
  return <Line ref={ref} points={points} color="#6366f1" lineWidth={1} transparent opacity={0.07} />;
}

/* ── Traveling signal particle ── */
function SignalParticle({ nodeA, nodeB, color, speed, offset }) {
  const ref = useRef();
  const t = useRef(offset % 1);
  const curve = useMemo(() => {
    const a = new THREE.Vector3(...nodeA.pos);
    const b = new THREE.Vector3(...nodeB.pos);
    const mid = new THREE.Vector3().addVectors(a, b).multiplyScalar(0.5)
      .add(new THREE.Vector3(0, 0.2, 0.1));
    return new THREE.CatmullRomCurve3([a, mid, b]);
  }, [nodeA, nodeB]);
  useFrame((_, delta) => {
    if (!ref.current) return;
    t.current = (t.current + delta * speed) % 1;
    ref.current.position.copy(curve.getPoint(t.current));
  });
  return (
    <group ref={ref}>
      <mesh>
        <sphereGeometry args={[0.055, 8, 8]} />
        <meshBasicMaterial color={color} />
      </mesh>
      <mesh>
        <sphereGeometry args={[0.13, 8, 8]} />
        <meshBasicMaterial color={color} transparent opacity={0.22}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

function NetworkScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    groupRef.current.rotation.y = Math.sin(clock.elapsedTime * 0.14) * 0.28;
    groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.09) * 0.06;
  });
  return (
    <group ref={groupRef}>
      {EDGES.map(([a, b], i) => <EdgeLine key={i} from={NODES[a]} to={NODES[b]} />)}
      {NODES.map((n) => <GlowNode key={n.id} pos={n.pos} color={n.color} />)}
      {SIGNAL_EDGES.map(([a, b], i) => (
        <SignalParticle key={i} nodeA={NODES[a]} nodeB={NODES[b]}
          color={NODES[b].color} speed={0.28 + i * 0.04} offset={i * 0.18} />
      ))}
    </group>
  );
}

/* ── Lazy-mount wrapper — only create WebGL context when in view ── */
function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const NeuralNetwork3D = () => (
  <div className="nn3d-wrap">
    <div className="nn3d-header">
      <p className="nn3d-subtitle">Signal flows from raw tech inputs to analytics outputs</p>
    </div>
    <div className="nn3d-canvas" aria-hidden="true">
      <LazyCanvas
        camera={{ position: [0, 0, 5.5], fov: 50 }}
        gl={{ antialias: true, alpha: false }}
        onCreated={({ gl }) => gl.setClearColor("#010108", 1)}
      >
        <NetworkScene />
      </LazyCanvas>
    </div>
    <div className="nn3d-legend">
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#60a5fa" }} />Input</div>
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#e8b99a" }} />Processing</div>
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#4ade80" }} />Output</div>
    </div>
  </div>
);

export default NeuralNetwork3D;
